const getDownlinkLossByTestPhase = `-- name: GetDownlinkLossByTestPhase :many
SELECT ID, ConfigName, TestPhaseName, Profile FROM "DownlinkLoss" WHERE "TestPhaseName" LIKE ?
`

func (q *Queries) GetDownlinkLossByTestPhase(ctx context.Context, testphasename string) ([]DownlinkLoss, error) {
	rows, err := q.db.QueryContext(ctx, getDownlinkLossByTestPhase, testphasename)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []DownlinkLoss
	for rows.Next() {
		var i DownlinkLoss
		if err := rows.Scan(
			&i.ID,
			&i.ConfigName,
			&i.TestPhaseName,
			&i.Profile,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

