const getUplinkLossByTestPhase = `-- name: GetUplinkLossByTestPhase :many

SELECT ID, ConfigName, TestPhaseName, Profile FROM "UplinkLoss" WHERE "TestPhaseName" LIKE ?
`

// From LossRelated.go
func (q *Queries) GetUplinkLossByTestPhase(ctx context.Context, testphasename string) ([]UplinkLoss, error) {
	rows, err := q.db.QueryContext(ctx, getUplinkLossByTestPhase, testphasename)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []UplinkLoss
	for rows.Next() {
		var i UplinkLoss
		if err := rows.Scan(
			&i.ID,
			&i.ConfigName,
			&i.TestPhaseName,
			&i.Profile,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

